/* PasstheEPPP — Expanded Question Bank Batch 5 (Large) */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch5 = [
        // ===== Domain 1: Biological Bases (10) =====
        {domainId:1, q:"The basal ganglia are primarily involved in:", options:["Language comprehension","Voluntary motor control and procedural learning","Visual processing","Regulation of body temperature"], answer:1, difficulty:"medium", rationale:"The basal ganglia (caudate, putamen, globus pallidus) are critical for voluntary motor control, procedural learning, habit formation, and action selection. Dysfunction is central to Parkinson's (hypokinesia) and Huntington's (hyperkinesia) diseases. They also contribute to reward-based learning and executive function."},
        {domainId:1, q:"Which type of brain imaging technique provides the best temporal resolution?", options:["fMRI","PET scan","EEG/ERP","CT scan"], answer:2, difficulty:"medium", rationale:"EEG (electroencephalography) and ERPs (event-related potentials) provide millisecond-level temporal resolution, capturing the real-time electrical activity of the brain. fMRI has excellent spatial resolution but poor temporal resolution (seconds), as it measures blood oxygen changes that lag behind neural activity. PET and CT have even poorer temporal resolution."},
        {domainId:1, q:"Neuroplasticity refers to:", options:["The brain's inability to change after critical periods","The brain's ability to reorganize neural pathways based on experience","The fixed nature of neural connections after birth","The hardening of neural tissue with age"], answer:1, difficulty:"easy", rationale:"Neuroplasticity is the brain's ability to reorganize itself by forming new neural connections throughout life. This occurs through mechanisms including synaptogenesis, synaptic pruning, long-term potentiation, and cortical remapping. Plasticity is greatest during development but continues into adulthood, which is the basis for rehabilitation after brain injury."},
        {domainId:1, q:"The thalamus is often described as the brain's:", options:["Emotional center","Relay station for sensory information","Primary motor area","Memory consolidation center"], answer:1, difficulty:"easy", rationale:"The thalamus acts as the brain's sensory relay station, routing nearly all incoming sensory information (except olfaction) to the appropriate cortical areas for processing. It also plays roles in consciousness, sleep-wake regulation, alertness, and motor functions. Each sensory modality has a specific thalamic nucleus."},
        {domainId:1, q:"Phantom limb pain is best explained by:", options:["Peripheral nerve damage at the amputation site","Cortical reorganization in the somatosensory cortex","Psychological denial of limb loss","Sympathetic nervous system dysfunction"], answer:1, difficulty:"hard", rationale:"Ramachandran's research demonstrated that phantom limb sensations result from cortical reorganization — neighboring areas in the somatosensory cortex invade the territory previously representing the amputated limb. For example, touching the face may produce sensations in the phantom hand because the face and hand areas are adjacent in the somatosensory homunculus."},
        {domainId:1, q:"The cerebellum is primarily responsible for:", options:["Language production","Motor coordination, balance, and procedural memory","Emotional regulation","Executive decision-making"], answer:1, difficulty:"easy", rationale:"The cerebellum ('little brain') contains more neurons than the rest of the brain combined and is critical for motor coordination, balance, timing, and procedural/motor learning. Cerebellar damage produces ataxia (uncoordinated movement), intention tremor, and dysarthria. Recent research also implicates the cerebellum in cognitive and emotional processing."},
        {domainId:1, q:"Serotonin syndrome is most likely to occur from:", options:["SSRI withdrawal","Combining two or more serotonergic medications","Taking a single dose of an SSRI","Chronic benzodiazepine use"], answer:1, difficulty:"medium", rationale:"Serotonin syndrome results from excessive serotonergic activity, most commonly from combining serotonergic drugs (e.g., SSRIs + MAOIs, SSRIs + triptans, SSRIs + tramadol). Symptoms include agitation, tremor, hyperthermia, tachycardia, and in severe cases, seizures and death. It is a medical emergency requiring immediate discontinuation of serotonergic agents."},
        {domainId:1, q:"Which structure connects the hippocampus to the hypothalamus and is damaged in Korsakoff's syndrome?", options:["Corpus callosum","Fornix and mammillary bodies","Anterior commissure","Arcuate fasciculus"], answer:1, difficulty:"hard", rationale:"Korsakoff's syndrome, a chronic sequel to Wernicke's encephalopathy from thiamine deficiency, involves damage to the mammillary bodies and the fornix (the main output pathway of the hippocampus). This disrupts the Papez circuit, producing severe anterograde amnesia, confabulation, and apathy. It is most commonly seen in chronic alcoholism."},
        {domainId:1, q:"Glutamate is the brain's primary:", options:["Inhibitory neurotransmitter","Excitatory neurotransmitter","Neuromodulator","Neuropeptide"], answer:1, difficulty:"easy", rationale:"Glutamate is the most abundant excitatory neurotransmitter in the CNS, involved in nearly every major excitatory brain function. It plays critical roles in learning, memory (via NMDA receptors and LTP), and neural development. Excessive glutamate activity (excitotoxicity) can cause neuronal death and is implicated in stroke, traumatic brain injury, and neurodegenerative diseases."},
        {domainId:1, q:"The default mode network (DMN) is most active when:", options:["Performing a demanding cognitive task","At rest, during mind-wandering and self-referential thought","During REM sleep only","Processing external sensory stimuli"], answer:1, difficulty:"hard", rationale:"The default mode network (medial prefrontal cortex, posterior cingulate, angular gyrus) is most active during rest, when the mind wanders, during self-referential thought, and when imagining the future or recalling the past. It deactivates during externally focused tasks. Altered DMN activity has been found in depression, ADHD, schizophrenia, and Alzheimer's disease."},

        // ===== Domain 2: Cognitive-Affective (10) =====
        {domainId:2, q:"The generation effect in memory refers to:", options:["Better recall for information that was self-generated vs. passively read","Enhanced memory for the first items in a list","Improved memory through spaced practice","The tendency to remember incomplete tasks better"], answer:0, difficulty:"medium", rationale:"The generation effect demonstrates that actively generating information (e.g., completing a word fragment, creating examples) produces better retention than passively reading the same material. This has important implications for studying: creating your own practice questions, elaborating on concepts, and teaching material to others are more effective than simply re-reading notes."},
        {domainId:2, q:"The Zeigarnik effect states that:", options:["Completed tasks are remembered better than incomplete ones","Incomplete or interrupted tasks are remembered better than completed ones","Memory declines exponentially over time","Emotional memories are more accurate than neutral ones"], answer:1, difficulty:"medium", rationale:"Bluma Zeigarnik (1927) found that people remember uncompleted or interrupted tasks better than completed ones. The tension of incompletion keeps the task mentally active. This effect has been applied to understanding rumination in depression, the effectiveness of cliffhangers in media, and study strategies (taking breaks during study can maintain cognitive engagement)."},
        {domainId:2, q:"Functional fixedness is the tendency to:", options:["View objects only in terms of their typical use","Fix attention on a single aspect of a problem","Use only well-practiced problem-solving strategies","Fixate on the first solution that comes to mind"], answer:0, difficulty:"easy", rationale:"Functional fixedness (Duncker, 1945) is a cognitive bias that limits a person to seeing an object only in the way it is traditionally used (e.g., not thinking to use a shoe as a hammer). It is a subset of mental set — the tendency to approach problems in fixed ways. Overcoming functional fixedness requires divergent thinking and the ability to reconceptualize objects' potential uses."},
        {domainId:2, q:"The testing effect (retrieval practice) demonstrates that:", options:["Studying more is always better than testing","Taking practice tests enhances long-term retention more than re-studying","Multiple-choice tests are more effective than free recall","Testing increases anxiety and impairs learning"], answer:1, difficulty:"medium", rationale:"The testing effect (Roediger & Karpicke, 2006) is one of the most robust findings in cognitive psychology: actively retrieving information from memory (via practice tests, flashcards, self-quizzing) strengthens memory traces more than repeated studying of the same material. This is why this app's quiz-based approach is evidence-based!"},
        {domainId:2, q:"The spacing effect suggests that:", options:["Massed practice is more effective than distributed practice","Distributed study sessions produce better long-term retention than cramming","Studying in the same location always improves recall","Short study sessions are always better than long ones"], answer:1, difficulty:"easy", rationale:"The spacing effect (Ebbinghaus, 1885) shows that distributing study across multiple sessions over time produces superior long-term retention compared to massing the same amount of study into one session (cramming). The optimal spacing interval depends on the desired retention interval. This principle underlies spaced repetition systems like the SM-2 algorithm used in this app."},
        {domainId:2, q:"According to Schachter and Singer's two-factor theory of emotion:", options:["Emotions are purely physiological responses","Emotions require both physiological arousal AND cognitive labeling","Cognitive appraisal always precedes physiological arousal","Facial expressions directly cause emotional experience"], answer:1, difficulty:"medium", rationale:"Schachter and Singer (1962) proposed that emotional experience requires two components: (1) physiological arousal and (2) a cognitive label for that arousal based on environmental cues. Their experiment showed that the same physiological state (epinephrine injection) could be experienced as either euphoria or anger depending on social context. This theory bridges the James-Lange and Cannon-Bard perspectives."},
        {domainId:2, q:"Prospective memory refers to:", options:["Remembering events from the past","Remembering to perform future intended actions","Memory for personal autobiographical events","The ability to mentally time-travel"], answer:1, difficulty:"easy", rationale:"Prospective memory is 'remembering to remember' — recalling that you need to perform a planned action in the future (e.g., remembering to take medication at 2 PM, remembering to call someone back). It declines with aging and is impaired in ADHD and early-stage dementia. External cues (alarms, lists) are effective compensatory strategies."},
        {domainId:2, q:"The peak-end rule (Kahneman) states that:", options:["People judge experiences by their peak intensity and how they ended, not by the average","People always remember the beginning of an experience most clearly","Emotional experiences are always remembered accurately","The most intense moment of an experience determines overall satisfaction"], answer:0, difficulty:"medium", rationale:"Kahneman's peak-end rule demonstrates that people evaluate past experiences based on: (1) the peak moment (most intense point) and (2) the ending, rather than the duration or average experience. This has implications for clinical work — ending therapy sessions on a positive note and addressing peak distress moments can shape how clients remember treatment."},
        {domainId:2, q:"Inattentional blindness (Simons & Chabris) demonstrates that:", options:["Attention is unlimited","People can fail to notice unexpected events when attention is focused elsewhere","Blindness always affects attention","Visual processing occurs without attention"], answer:1, difficulty:"easy", rationale:"The famous 'invisible gorilla' study (Simons & Chabris, 1999) showed that approximately 50% of observers focused on counting basketball passes failed to notice a person in a gorilla suit walking through the scene. This demonstrates that attention is a limited resource — when focused on one task, we can be functionally blind to unexpected but clearly visible events."},
        {domainId:2, q:"The endowment effect in behavioral economics refers to:", options:["People's tendency to lose more money than they gain","People valuing items they own more highly than identical items they don't own","The economic advantage of early investment","The tendency to hoard possessions"], answer:1, difficulty:"medium", rationale:"The endowment effect (Thaler, 1980; Kahneman et al., 1990) demonstrates that people assign more value to things they own compared to identical items they don't own. For example, people demand a higher price to sell a coffee mug they were given than they would pay to buy the same mug. This violates rational economic assumptions and relates to loss aversion."},

        // ===== Domain 3: Social & Cultural (10) =====
        {domainId:3, q:"Implicit bias, as measured by the Implicit Association Test (IAT), refers to:", options:["Consciously held prejudicial attitudes","Unconscious automatic associations between social groups and evaluations","Deliberate discrimination in hiring practices","Self-reported racial attitudes"], answer:1, difficulty:"medium", rationale:"The IAT (Greenwald et al., 1998) measures implicit (unconscious) biases by comparing reaction times when pairing social groups (e.g., racial groups) with positive vs. negative attributes. People respond faster to pairings consistent with their implicit associations. IAT scores often differ from explicit self-reports, suggesting that implicit and explicit attitudes are distinct constructs."},
        {domainId:3, q:"According to realistic conflict theory (Sherif), intergroup prejudice arises from:", options:["Innate aggressive tendencies","Competition between groups for scarce resources","Individual personality flaws","Social learning of stereotypes"], answer:1, difficulty:"medium", rationale:"Sherif's Robbers Cave experiment (1961) demonstrated that intergroup hostility arose when groups competed for limited resources (realistic conflict) and was reduced through superordinate goals requiring intergroup cooperation. This theory explains prejudice as a rational (if destructive) response to perceived resource competition, in contrast to personality-based explanations."},
        {domainId:3, q:"The actor-observer bias suggests that:", options:["Actors and observers always agree on the cause of behavior","Actors attribute their behavior to situations while observers attribute the same behavior to dispositions","Observers are always more accurate than actors","Actors overestimate their own abilities"], answer:1, difficulty:"medium", rationale:"The actor-observer asymmetry (Jones & Nisbett, 1971) extends the fundamental attribution error: when explaining our OWN behavior, we emphasize situational factors ('I was late because of traffic'), but when explaining OTHERS' behavior, we emphasize dispositional factors ('They're always late because they're irresponsible'). This asymmetry arises partly from different visual perspectives and different information access."},
        {domainId:3, q:"Helms' White Racial Identity Development model includes which stage?", options:["Encounter","Immersion-Emersion","Contact","Pre-encounter"], answer:2, difficulty:"hard", rationale:"Helms' White Racial Identity model includes six statuses: Contact (oblivious to racial issues), Disintegration (first awareness of racism, guilt), Reintegration (idealizing White superiority), Pseudo-independence (intellectual understanding of racism), Immersion-Emersion (honest appraisal of White identity), and Autonomy (internalized positive, non-racist White identity). Contact, Disintegration, and Reintegration characterize the less developed statuses."},
        {domainId:3, q:"Cognitive load theory suggests that prejudice and stereotyping increase when:", options:["People are well-rested and cognitively fresh","People have unlimited time to make judgments","People are under cognitive load or time pressure","People are in diverse environments"], answer:2, difficulty:"medium", rationale:"Stereotyping can function as a cognitive shortcut that conserves mental resources. When people are cognitively overloaded (multitasking, time pressure, fatigue, intoxication), they rely more heavily on stereotypes because they lack the cognitive resources needed for individuated processing. This has important implications for decision-making in settings like emergency rooms, hiring, and law enforcement."},
        {domainId:3, q:"Social loafing refers to:", options:["Working harder when in a group","Exerting less effort when working in a group than when working alone","Refusing to participate in group activities","Being lazier during social events"], answer:1, difficulty:"easy", rationale:"Social loafing (Latané et al., 1979) occurs when individuals exert less effort on a collective task than on an individual task. It is reduced when: individual contributions are identifiable, the task is meaningful, the group is small, and group cohesion is high. Cultural differences exist — social loafing is less common in collectivistic cultures where group performance is valued."},
        {domainId:3, q:"The self-serving bias is the tendency to:", options:["Attribute successes to internal factors and failures to external factors","Always blame others for negative outcomes","Overestimate one's abilities in all situations","Seek out feedback that confirms self-concept"], answer:0, difficulty:"easy", rationale:"The self-serving bias protects self-esteem by attributing positive outcomes to one's own abilities or effort (internal) and negative outcomes to external circumstances, bad luck, or other people. While generally considered a normal self-protective mechanism, it can become problematic when excessive (narcissism) or absent (depressive attributional style, where people blame themselves for failures)."},
        {domainId:3, q:"White privilege, as described by McIntosh (1988), refers to:", options:["Economic advantages held by all White individuals","Unearned advantages and immunities that benefit White individuals in society","The belief that White culture is superior","Deliberate acts of racism by White individuals"], answer:1, difficulty:"medium", rationale:"Peggy McIntosh's (1988) 'Invisible Knapsack' conceptualized White privilege as an invisible set of unearned assets that White people can count on daily but are taught not to recognize. It includes advantages like seeing one's race positively represented in media, not being followed in stores, and being able to move through life without race being a barrier. Understanding privilege is distinct from personal guilt."},
        {domainId:3, q:"Deindividuation occurs when:", options:["Individuals gain a strong sense of personal identity in groups","Individuals lose self-awareness and self-regulation in group settings","Groups become more cohesive over time","Leaders emerge naturally in group settings"], answer:1, difficulty:"easy", rationale:"Deindividuation theory (Zimbardo, 1969) proposes that conditions like anonymity, reduced accountability, and arousal lead people to lose self-awareness and abandon normal behavioral restraints. This concept has been applied to understanding mob behavior, online trolling, and the effects of uniforms/disguises on aggression. It contributed to the design of the Stanford Prison Experiment."},
        {domainId:3, q:"Ecological systems theory (Bronfenbrenner) emphasizes that development occurs within:", options:["A single family context","Multiple nested environmental systems","Only peer group influences","Primarily genetic determinism"], answer:1, difficulty:"easy", rationale:"Bronfenbrenner's ecological systems theory conceptualizes development within five nested systems: microsystem (family, school), mesosystem (connections between microsystems), exosystem (indirect influences like parent's workplace), macrosystem (cultural values, laws), and chronosystem (historical changes over time). This framework highlights that development cannot be understood outside of its ecological context."},

        // ===== Domain 4: Growth & Lifespan (10) =====
        {domainId:4, q:"Object permanence, according to Piaget, develops during which substage of the sensorimotor period?", options:["Substage 1 (0-1 month)","Substage 4 (8-12 months)","Substage 6 (18-24 months)","It is present at birth"], answer:1, difficulty:"medium", rationale:"Object permanence (understanding that objects continue to exist when not visible) begins to develop around substage 4 (8-12 months), though it is not fully mature until substage 6 (18-24 months). The classic A-not-B error (searching where the object was last found rather than where it was actually hidden) occurs during substage 4 and resolves in substage 5."},
        {domainId:4, q:"According to Levinson's theory, the 'midlife transition' occurs approximately at age:", options:["25-30","35-40","40-45","50-55"], answer:2, difficulty:"medium", rationale:"Levinson's Seasons of a Man's Life (1978) identifies the midlife transition at ages 40-45 as a major developmental turning point. During this period, individuals reassess their life structure, confront mortality, and may make significant life changes. While popularly termed 'midlife crisis,' Levinson viewed it as a normative transition that varies greatly in intensity across individuals."},
        {domainId:4, q:"Chomsky's concept of a Language Acquisition Device (LAD) proposes that:", options:["Language is entirely learned through reinforcement","Humans have an innate, biological capacity for language learning","Language development depends solely on environmental input","Children can only learn language through formal instruction"], answer:1, difficulty:"easy", rationale:"Chomsky's nativist theory proposes that humans possess an innate Language Acquisition Device — a biological endowment that predisposes children to acquire language. Evidence includes: universal language milestones, the poverty of the stimulus argument (children produce sentences they've never heard), sensitive periods for language, and the existence of universal grammar structures across all languages."},
        {domainId:4, q:"Authoritative parenting (Baumrind) is characterized by:", options:["High demandingness, low responsiveness","Low demandingness, high responsiveness","High demandingness, high responsiveness","Low demandingness, low responsiveness"], answer:2, difficulty:"easy", rationale:"Baumrind's (1966) four parenting styles: Authoritative (high demand + high response = best outcomes), Authoritarian (high demand + low response = obedient but less happy), Permissive (low demand + high response = impulsive children), and Neglectful (low demand + low response = worst outcomes). Research consistently shows authoritative parenting is associated with the best academic, social, and emotional outcomes."},
        {domainId:4, q:"The 'goodness of fit' model proposes that:", options:["Only easy temperament children develop well","Developmental outcomes depend on the match between a child's temperament and environmental demands","Parents should always adapt their style to match the child","Temperament is entirely determined by parenting"], answer:1, difficulty:"medium", rationale:"Thomas and Chess's goodness of fit model proposes that developmental outcomes depend on the compatibility between the child's temperament and the demands/expectations of the environment. A 'difficult' child with patient, flexible caregivers may do well, while an 'easy' child in a chaotic environment may struggle. This interaction perspective avoids blaming either the child or the parent."},
        {domainId:4, q:"Adolescent egocentrism (Elkind) includes the concepts of:", options:["Object permanence and conservation","Personal fable and imaginary audience","Identity vs. role confusion","Formal operations and abstract thinking"], answer:1, difficulty:"easy", rationale:"Elkind (1967) described two aspects of adolescent egocentrism: the imaginary audience (believing others are watching and evaluating you, leading to self-consciousness) and the personal fable (believing one's experiences and feelings are unique and that one is invulnerable — 'it won't happen to me'). These concepts help explain adolescent risk-taking and hyperself-consciousness."},
        {domainId:4, q:"Critical periods in development differ from sensitive periods in that:", options:["Critical periods are less important than sensitive periods","Critical periods have a more rigid time window after which learning becomes extremely difficult or impossible","Sensitive periods apply only to cognitive development","There is no meaningful difference between the two"], answer:1, difficulty:"medium", rationale:"Critical periods are time-limited windows during which specific experiences MUST occur for normal development (e.g., imprinting in birds, visual cortex development). Sensitive periods are broader windows during which the organism is especially responsive to certain environmental inputs, but learning can still occur outside this window, albeit with greater difficulty (e.g., language acquisition)."},
        {domainId:4, q:"Scaffolding in the context of cognitive development involves:", options:["Providing permanent support structures for learning","Adjusting the level of support based on the learner's current performance and gradually withdrawing it","Allowing children to explore without any adult guidance","Building physical structures for children to climb"], answer:1, difficulty:"easy", rationale:"Scaffolding (Wood, Bruner & Ross, 1976) involves providing calibrated support that matches the learner's needs, then systematically fading it as competence increases. For example, a parent might first demonstrate a task, then guide the child through it, then offer verbal prompts only, and finally allow independent performance. This dynamic support within the ZPD is central to effective instruction."},
        {domainId:4, q:"Kübler-Ross's stage model of grief has been criticized primarily because:", options:["It was based on too large a sample","Research does not consistently support a fixed sequence of stages","It accounts for cultural differences too well","It only applies to sudden death"], answer:1, difficulty:"medium", rationale:"While influential, the Kübler-Ross model has been criticized for: (1) lack of empirical support for grief occurring in a fixed sequence, (2) risk of pathologizing normal grief responses that don't follow the stages, (3) limited sample (primarily terminal cancer patients), and (4) cultural bias. Modern grief research (e.g., Worden's tasks, Stroebe's dual process model) emphasizes that grief is highly individual and non-linear."},
        {domainId:4, q:"Teratogenic effects on fetal development are most severe during:", options:["The germinal period (0-2 weeks)","The embryonic period (3-8 weeks)","The fetal period (9 weeks to birth)","The neonatal period (birth to 1 month)"], answer:1, difficulty:"medium", rationale:"The embryonic period (weeks 3-8) is when major organ systems are forming (organogenesis), making it the period of greatest vulnerability to teratogens. During this time, substances like alcohol, certain medications, and infections can cause major structural abnormalities. The fetal period (9 weeks+) is still vulnerable but primarily to functional and growth effects rather than major structural malformations."},

        // ===== Domain 5: Assessment (10) =====
        {domainId:5, q:"The Halstead-Reitan Neuropsychological Battery is used primarily to:", options:["Diagnose personality disorders","Assess cognitive functioning and brain damage","Measure intelligence in children","Screen for depression"], answer:1, difficulty:"medium", rationale:"The Halstead-Reitan is a comprehensive neuropsychological battery that assesses multiple cognitive domains including attention, memory, language, motor skills, abstract reasoning, and sensory-perceptual functioning. It can help identify the presence, lateralization, and localization of brain damage, as well as differentiate between different neurological conditions. It is often complemented with additional tests."},
        {domainId:5, q:"Base rate in diagnostic testing refers to:", options:["The standard scoring system used","The prevalence of a condition in the population being tested","The cost of administering the test","The minimum score needed for diagnosis"], answer:1, difficulty:"medium", rationale:"Base rate is the prevalence of a condition in the specific population being tested. It dramatically affects the positive predictive value of a test. A test with 95% sensitivity and 95% specificity will have very different positive predictive values depending on whether the base rate is 50% (most positives are true) vs. 1% (most positives are false). Ignoring base rates is a common clinical reasoning error."},
        {domainId:5, q:"Flynn effect refers to:", options:["The decline in test scores over generations","The observed rise in average IQ scores over successive generations","The tendency for test-retest scores to decrease","The impact of cultural bias on IQ test scores"], answer:1, difficulty:"medium", rationale:"The Flynn effect (Flynn, 1984) refers to the substantial and sustained increase in IQ scores worldwide over the 20th century (approximately 3 IQ points per decade). Possible explanations include improved nutrition, increased education, smaller family sizes, environmental enrichment, and greater familiarity with testing. This necessitates periodic re-norming of IQ tests to maintain accurate standard scores."},
        {domainId:5, q:"Content validity is established by:", options:["Correlating test scores with a criterion measure","Expert judgment that the test items adequately sample the construct domain","Demonstrating consistent scores across administrations","Factor analyzing the test items"], answer:1, difficulty:"easy", rationale:"Content validity assesses whether test items adequately and representatively sample the domain of interest. Unlike criterion or construct validity, content validity is primarily established through expert judgment — subject matter experts evaluate whether items cover the full breadth and depth of the construct. Content validity is particularly important for achievement tests and certification exams like the EPPP."},
        {domainId:5, q:"In classical test theory, an observed score is comprised of:", options:["The true score only","The true score plus measurement error","The standard deviation plus the mean","The reliability coefficient times the validity coefficient"], answer:1, difficulty:"medium", rationale:"Classical test theory (CTT) posits that any observed score (X) equals the true score (T) plus error (E): X = T + E. Error is assumed to be random and normally distributed with a mean of zero. This model underlies reliability estimation — if errors are small and random, the observed score closely approximates the true score. Higher reliability means less error and more accurate measurement."},
        {domainId:5, q:"The NEO-PI-R measures:", options:["Psychopathology and symptom severity","The Big Five personality traits","Cognitive abilities and IQ","Adaptive behavior in daily functioning"], answer:1, difficulty:"easy", rationale:"The NEO Personality Inventory-Revised measures the Big Five personality factors (OCEAN): Openness to Experience, Conscientiousness, Extraversion, Agreeableness, and Neuroticism. Each factor contains six facet scales. It is widely used in personality research, clinical assessment, and vocational counseling. The Big Five model is the most empirically supported dimensional model of personality."},
        {domainId:5, q:"Regression to the mean refers to:", options:["The tendency for extreme scores to move toward the average on retesting","A statistical method for predicting one variable from another","The decline in test performance over time","The averaging of scores within a normative sample"], answer:0, difficulty:"medium", rationale:"Regression to the mean is a statistical phenomenon where extreme scores on one measurement tend to be less extreme on subsequent measurements. This occurs naturally due to random error and has important clinical implications: a very depressed patient may improve somewhat on retesting simply due to regression, not treatment. This is why control groups are essential in treatment outcome research."},
        {domainId:5, q:"Malingering differs from factitious disorder in that:", options:["Malingering involves unconscious symptom production","Factitious disorder has external incentives like financial gain","Malingering involves conscious faking for external gain","Both are identical diagnostic categories"], answer:2, difficulty:"medium", rationale:"Malingering involves conscious, deliberate fabrication or exaggeration of symptoms motivated by external incentives (financial compensation, avoiding work/military service, obtaining medications). Factitious disorder also involves conscious symptom production but is motivated by the internal psychological need to assume the sick role. Somatoform/somatic symptom disorders involve genuine distress without conscious fabrication."},
        {domainId:5, q:"Item Response Theory (IRT) differs from Classical Test Theory (CTT) in that:", options:["IRT focuses on the total test score","IRT models the probability of a correct response based on item and person parameters","CTT is more modern than IRT","IRT cannot be used for adaptive testing"], answer:1, difficulty:"hard", rationale:"IRT models the relationship between a person's ability level and the probability of answering each item correctly, using parameters like item difficulty, discrimination, and guessing. Unlike CTT (which focuses on total scores), IRT enables: computer adaptive testing, item difficulty estimation independent of the sample, and person ability estimation independent of the specific items. The EPPP uses IRT-based scoring."},
        {domainId:5, q:"Cultural test bias refers to:", options:["All psychological tests being unfair to minorities","Systematic measurement error that leads to differential prediction or item functioning across groups","The intentional discrimination against specific cultural groups in testing","The inability to translate tests into other languages"], answer:1, difficulty:"medium", rationale:"Cultural test bias is a psychometric concept referring to systematic error that causes tests to function differently for different cultural, ethnic, or demographic groups beyond actual differences in the construct being measured. Differential Item Functioning (DIF) analysis identifies biased items. Bias is a technical measurement concept distinct from test fairness (a broader social/philosophical issue about how test scores are used)."},

        // ===== Domain 6: Treatment (10) =====
        {domainId:6, q:"In behavioral activation for depression, the primary mechanism of change is:", options:["Identifying and challenging cognitive distortions","Increasing engagement in rewarding activities to counteract withdrawal and avoidance","Processing past traumatic experiences","Developing insight into unconscious conflicts"], answer:1, difficulty:"medium", rationale:"Behavioral activation (BA) targets the withdrawal and avoidance that maintain depression. Rather than focusing on cognitions (as in CBT), BA helps clients schedule and engage in valued activities, creating opportunities for positive reinforcement. Research shows BA is as effective as full CBT for depression and may be easier to disseminate. Activity monitoring and scheduling are core techniques."},
        {domainId:6, q:"The working alliance, according to Bordin (1979), consists of:", options:["Transference and countertransference","Goals, tasks, and bond","Empathy, congruence, and UPR","Assessment, intervention, and termination"], answer:1, difficulty:"medium", rationale:"Bordin's pantheoretical model of the working alliance includes three components: (1) agreement on therapeutic goals, (2) agreement on tasks and methods to achieve those goals, and (3) the emotional bond between therapist and client. Research consistently shows the alliance is one of the strongest predictors of psychotherapy outcomes regardless of theoretical orientation."},
        {domainId:6, q:"Motivational interviewing was originally developed to treat:", options:["Anxiety disorders","Substance use disorders","Eating disorders","Personality disorders"], answer:1, difficulty:"easy", rationale:"William Miller developed Motivational Interviewing (MI) in the 1980s specifically for treating alcohol use disorders, later expanding it with Stephen Rollnick to address broader behavior change. MI uses the 'spirit' of collaboration, evocation, and autonomy with core skills (OARS: Open questions, Affirming, Reflecting, Summarizing) to resolve ambivalence and elicit intrinsic motivation for change."},
        {domainId:6, q:"The concept of 'common factors' in psychotherapy most strongly suggests that:", options:["All therapies are identical in their approach","Factors shared across therapies (alliance, empathy, expectations) account for much of therapy's effectiveness","Specific techniques don't matter at all","Therapist training is unnecessary"], answer:1, difficulty:"medium", rationale:"Common factors theory (Wampold, 2001) proposes that elements shared across therapies — therapeutic alliance, therapist empathy, positive expectations, rationale/framework — account for more outcome variance than specific techniques. Lambert's (1992) estimates: 40% extratherapeutic factors, 30% common factors, 15% expectancy, 15% specific techniques. This remains debated, with some evidence that specific techniques matter more for certain disorders."},
        {domainId:6, q:"Exposure and Response Prevention (ERP) is the first-line treatment for:", options:["Generalized anxiety disorder","Obsessive-compulsive disorder","Post-traumatic stress disorder","Social anxiety disorder"], answer:1, difficulty:"easy", rationale:"ERP is the gold-standard psychotherapy for OCD. It involves: (1) Exposure — systematic confrontation with feared stimuli, situations, or thoughts that trigger obsessions, and (2) Response Prevention — refraining from performing compulsive rituals. By preventing the ritual, the client learns that anxiety naturally decreases without the compulsion (habituation) and that feared consequences don't occur (inhibitory learning)."},
        {domainId:6, q:"Bowen's family systems therapy emphasizes:", options:["Structural changes in family hierarchies","Differentiation of self from the emotional family system","Strategic interventions and homework assignments","Solution-focused brief techniques"], answer:1, difficulty:"medium", rationale:"Murray Bowen's family systems theory centers on differentiation of self — the ability to separate one's intellectual and emotional functioning and to maintain a clear sense of self within emotionally intense family relationships. Key concepts include emotional triangles, multigenerational transmission, emotional cutoff, nuclear family emotional system, and the genogram as an assessment tool."},
        {domainId:6, q:"Prolonged Exposure (PE) therapy for PTSD involves:", options:["Brief 3-session treatment","Imaginal and in vivo exposure to trauma memories and reminders","Medication management only","Cognitive restructuring without any exposure"], answer:1, difficulty:"easy", rationale:"Prolonged Exposure (Foa et al.) is an evidence-based PTSD treatment including: (1) psychoeducation, (2) breathing retraining, (3) in vivo exposure to safe but avoided situations/places reminiscent of the trauma, and (4) imaginal exposure — repeatedly recounting the trauma memory in detail until the emotional response diminishes. PE is based on emotional processing theory and has strong empirical support."},
        {domainId:6, q:"In narrative therapy, 'externalization' involves:", options:["Blaming external factors for problems","Separating the problem from the person's identity","Expressing emotions outwardly","Describing events in chronological order"], answer:1, difficulty:"medium", rationale:"Externalization (White & Epston, 1990) is a core narrative therapy technique that linguistically separates the problem from the person ('The depression is affecting you' vs. 'You are depressed'). This creates space between the person and the problem, reduces shame, and allows the person to develop a relationship with the problem rather than being defined by it. 'The person is not the problem; the problem is the problem.'"},
        {domainId:6, q:"The dose-response relationship in psychotherapy suggests that:", options:["More sessions always produce better outcomes","Most therapeutic gains occur in the early sessions, with diminishing returns over time","Therapy should always last at least one year","The number of sessions is unrelated to outcomes"], answer:1, difficulty:"medium", rationale:"Howard et al. (1986) found a negatively accelerated dose-response curve: approximately 50% of clients show clinically significant improvement by session 8, and 75% by session 26. This suggests early sessions produce the largest gains, with diminishing returns over time. However, complex presentations (personality disorders, chronic conditions) typically require longer treatment for meaningful change."},
        {domainId:6, q:"Interpersonal therapy (IPT) focuses primarily on:", options:["Unconscious conflicts","Current interpersonal problems and role transitions","Cognitive distortions","Past childhood experiences"], answer:1, difficulty:"easy", rationale:"IPT (Klerman & Weissman) is a time-limited, evidence-based treatment originally for depression that focuses on four interpersonal problem areas: grief, role disputes, role transitions, and interpersonal deficits. IPT addresses current relationships rather than cognitive patterns or unconscious conflicts. It is an empirically supported treatment for major depression, with adaptations for other disorders."},

        // ===== Domain 7: Research Methods (8) =====
        {domainId:7, q:"A mediating variable explains:", options:["The relationship between two unrelated variables","HOW or WHY the independent variable affects the dependent variable","The variance not accounted for by the independent variable","The boundary conditions of an effect"], answer:1, difficulty:"medium", rationale:"A mediator is an intervening variable that explains the mechanism through which X affects Y (X → M → Y). For example, CBT (X) may reduce depression (Y) through the mechanism of changing negative cognitions (M = mediator). Statistical mediation analysis (Baron & Kenny, 1986; bootstrapping methods) tests whether the indirect path through the mediator is significant."},
        {domainId:7, q:"A moderating variable specifies:", options:["The mechanism through which one variable affects another","WHEN or FOR WHOM the relationship between variables changes in strength or direction","The statistical significance of a correlation","The direction of causality between variables"], answer:1, difficulty:"medium", rationale:"A moderator specifies the conditions under which a relationship changes — it answers WHEN, FOR WHOM, or UNDER WHAT CONDITIONS an effect occurs. For example, treatment effectiveness (X→Y) might be moderated by severity — therapy may be very effective for mild depression but less so for severe depression. Moderators are tested through interaction effects in regression or ANOVA."},
        {domainId:7, q:"The Hawthorne effect refers to:", options:["Changes in behavior resulting from awareness of being observed","The tendency to conform to group norms","The placebo effect in clinical trials","Experimenter bias in data collection"], answer:0, difficulty:"easy", rationale:"The Hawthorne effect (originally from the Western Electric studies in the 1920s-30s) describes how research participants may change their behavior simply because they know they are being studied, independent of the actual experimental manipulation. This is a threat to internal validity and is addressed through blinding procedures, unobtrusive measures, and deception (with ethical approval)."},
        {domainId:7, q:"Statistical power is influenced by all of the following EXCEPT:", options:["Sample size","Effect size","Alpha level","The number of researchers conducting the study"], answer:3, difficulty:"easy", rationale:"Statistical power (probability of correctly rejecting a false null hypothesis) is determined by: (1) sample size (larger = more power), (2) effect size (larger = more power), (3) alpha level (larger alpha = more power but more Type I error), and (4) one-tailed vs. two-tailed test. The number of researchers is irrelevant to statistical power. Cohen recommended power of .80 as a minimum."},
        {domainId:7, q:"Content analysis as a research method involves:", options:["Analyzing the validity of test content","Systematically coding and analyzing text, media, or communication content","Evaluating the content of therapy sessions exclusively","Reviewing the contents of case files for legal proceedings"], answer:1, difficulty:"easy", rationale:"Content analysis is a systematic research method for analyzing text, images, video, or other communication content by coding it into defined categories. It can be quantitative (counting occurrences) or qualitative (identifying themes). It is used in psychology to analyze therapy transcripts, media representations, historical documents, social media posts, and other textual or visual data."},
        {domainId:7, q:"Demand characteristics in research refer to:", options:["The requirements placed on researchers by the IRB","Cues in the experiment that suggest to participants what behavior is expected","The statistical assumptions required for parametric tests","The resource demands of conducting research"], answer:1, difficulty:"easy", rationale:"Demand characteristics (Orne, 1962) are cues that convey the hypothesis to participants and may lead them to behave in ways they believe the researcher expects. This threatens internal validity because observed effects may be due to participant expectations rather than the actual manipulation. Counter-measures include: double-blind procedures, deception, cover stories, and manipulation checks."},
        {domainId:7, q:"In a multiple regression analysis, multicollinearity occurs when:", options:["The dependent variable is dichotomous","Two or more predictor variables are highly correlated with each other","The residuals are not normally distributed","The sample size is too small"], answer:1, difficulty:"medium", rationale:"Multicollinearity occurs when predictor variables in a regression model are highly intercorrelated, making it difficult to determine the unique contribution of each predictor. It inflates standard errors, reduces the significance of individual predictors, and produces unstable regression coefficients. Diagnostics include tolerance values and Variance Inflation Factors (VIF). Remedies include removing redundant predictors."},
        {domainId:7, q:"Grounded theory methodology is characterized by:", options:["Testing pre-existing theories using quantitative methods","Developing theory inductively from systematic data collection and analysis","Applying existing frameworks to new populations","Using large-scale surveys to confirm hypotheses"], answer:1, difficulty:"medium", rationale:"Grounded theory (Glaser & Strauss, 1967) is a qualitative methodology that generates theory from data through systematic collection, coding, and analysis. Key features include: theoretical sampling, constant comparative method, open/axial/selective coding, memoing, and theoretical saturation (collecting data until no new themes emerge). The resulting theory is 'grounded' in the actual data rather than imposed from existing frameworks."},

        // ===== Domain 8: Ethics (7) =====
        {domainId:8, q:"The Goldwater Rule in psychology/psychiatry refers to:", options:["The requirement to use evidence-based treatments","The ethical prohibition against diagnosing public figures without a personal evaluation","The rule that therapists must report child abuse","The standard for determining competency to stand trial"], answer:1, difficulty:"medium", rationale:"The Goldwater Rule (APA Psychiatric Ethics, Section 7.3) states that it is unethical for psychiatrists to give professional opinions about public figures they have not personally examined. Named after Barry Goldwater (1964 presidential campaign), it was reaffirmed in 2017. While specific to psychiatry, the principle applies broadly — psychologists should not diagnose individuals they have not properly assessed."},
        {domainId:8, q:"In forensic psychology, the concept of 'ultimate issue testimony' refers to:", options:["Expert testimony about the defendant's mental state at the time of the offense","Expert testimony that directly answers the legal question before the court","The final testimony given in a trial","Testimony about a person's character"], answer:1, difficulty:"hard", rationale:"Ultimate issue testimony occurs when an expert witness directly opines on the ultimate legal question (e.g., 'The defendant is not guilty by reason of insanity'). The Federal Rules of Evidence (Rule 704(b)) prohibit mental health experts from testifying about a criminal defendant's mental state as it relates to intent. Experts can describe the defendant's condition but should allow the trier of fact to draw the ultimate legal conclusion."},
        {domainId:8, q:"The ethical concept of 'justice' in the APA Ethics Code relates to:", options:["Punishing unethical behavior","Ensuring fairness and equal access to the benefits of psychology","The legal system's treatment of psychologists","Criminal justice psychology only"], answer:1, difficulty:"easy", rationale:"APA General Principle D (Justice) requires that psychologists recognize fairness and justice entitle all persons to access to and benefit from psychology. This includes recognizing how biases and limits of competence may lead to unjust practices. Justice considerations arise in areas like equitable access to mental health services, cultural bias in assessment, and fair treatment in research."},
        {domainId:8, q:"When a psychologist is asked to provide therapy to both divorcing spouses, this represents a potential:", options:["Informed consent issue only","Multiple relationship and conflict of interest","Confidentiality breach","Scope of practice issue"], answer:1, difficulty:"medium", rationale:"Providing therapy to both parties in a divorce creates a multiple relationship with inherent conflicts of interest — the therapeutic goals and confidences of one spouse may conflict with those of the other. APA Standard 3.05 (Multiple Relationships) and 10.02 (Therapy Involving Couples/Families) address this. The psychologist should typically decline or clarify roles, boundaries, and confidentiality limits from the outset."},
        {domainId:8, q:"HIPAA's Privacy Rule applies to:", options:["All psychologists regardless of setting","Only covered entities (healthcare providers, health plans, clearinghouses) that transmit health information electronically","Only hospital-based psychologists","Only psychologists who accept insurance"], answer:1, difficulty:"medium", rationale:"HIPAA applies specifically to 'covered entities' — healthcare providers who transmit protected health information (PHI) electronically. A psychologist in solo private practice who does not file electronic claims may not be a covered entity under HIPAA, though they remain bound by state confidentiality laws and APA Ethics Code. Business associates of covered entities are also regulated under HIPAA."},
        {domainId:8, q:"An ethical psychologist who realizes they lack competence in a client's presenting issue should:", options:["Continue treatment while reading about the topic","Immediately terminate the client","Seek consultation, supervision, or refer the client to a qualified professional","Ignore the issue and focus on areas of competence"], answer:2, difficulty:"easy", rationale:"APA Standard 2.01 (Boundaries of Competence) requires practicing within one's competence. When encountering areas outside their competence, psychologists should: (1) seek consultation or supervision, (2) obtain additional training/education, or (3) refer the client to a qualified professional. Immediate termination without providing referrals would itself be unethical (Standard 10.10)."},
        {domainId:8, q:"The psychologist-client privilege:", options:["Belongs to the psychologist","Belongs to the client and can only be waived by the client","Is identical in all 50 states","Can never be broken under any circumstances"], answer:1, difficulty:"medium", rationale:"Psychologist-client privilege is a legal right that belongs to the CLIENT, not the therapist. The client can waive privilege and authorize disclosure. The therapist cannot unilaterally waive privilege except in specific legally mandated situations (danger to self/others, child abuse, court orders). Privilege laws vary significantly by state, and psychologists must know their jurisdiction's specific laws regarding scope and exceptions."}
    ];

    batch5.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch5.length} additional questions (batch 5).`);
})();


