/* PasstheEPPP — Expanded Question Bank Batch 6
   Enhanced format: rationales now explain why EACH incorrect answer is wrong */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch6 = [
        // ===== Domain 1: Biological Bases (12) =====
        {domainId:1, q:"A patient with damage to the ventromedial prefrontal cortex would most likely exhibit:", options:["Severe memory impairment","Poor decision-making and impaired social/emotional judgment","Complete loss of language","Inability to recognize faces"], answer:1, difficulty:"hard", rationale:"Correct: (B) The ventromedial PFC integrates emotion into decision-making. Damage (as in Phineas Gage and Damasio's somatic marker hypothesis) produces poor judgment, impulsivity, and impaired social behavior despite intact IQ.\n\nWhy others are wrong:\n(A) Memory impairment → hippocampus, not vmPFC\n(C) Language loss → Broca's (left frontal) or Wernicke's (left temporal) areas\n(D) Face recognition loss (prosopagnosia) → fusiform face area in temporal lobe"},
        {domainId:1, q:"Which medication class works by blocking the reuptake of serotonin?", options:["Benzodiazepines","Tricyclic antidepressants","SSRIs","MAO inhibitors"], answer:2, difficulty:"easy", rationale:"Correct: (C) Selective Serotonin Reuptake Inhibitors (SSRIs) like fluoxetine (Prozac) specifically block the serotonin transporter, increasing serotonin availability in the synapse.\n\nWhy others are wrong:\n(A) Benzodiazepines enhance GABA activity at GABA-A receptors — they don't affect serotonin reuptake\n(B) Tricyclics block reuptake of BOTH serotonin AND norepinephrine (less selective), plus have anticholinergic side effects\n(D) MAO inhibitors prevent the enzyme monoamine oxidase from breaking down serotonin, norepinephrine, and dopamine — different mechanism than blocking reuptake"},
        {domainId:1, q:"The hypothalamus regulates all of the following EXCEPT:", options:["Body temperature","Hunger and thirst","Language production","Circadian rhythms"], answer:2, difficulty:"easy", rationale:"Correct: (C) Language production is controlled by Broca's area in the left frontal lobe, not the hypothalamus.\n\nWhy others are wrong:\n(A) Body temperature IS regulated by the hypothalamus — it acts as the body's thermostat\n(B) Hunger and thirst ARE regulated by the hypothalamus — lateral (hunger), ventromedial (satiety), and osmoreceptors\n(D) Circadian rhythms ARE regulated by the suprachiasmatic nucleus (SCN) in the hypothalamus"},
        {domainId:1, q:"A split-brain patient is shown an image only to the left visual field. The patient will:", options:["Be able to verbally identify the object","Not be able to verbally identify it but can point to it with the left hand","Not be able to perceive the image at all","Be able to identify it both verbally and by pointing"], answer:1, difficulty:"hard", rationale:"Correct: (B) Left visual field → right hemisphere (which lacks language centers in most people). The patient can't verbally name it but CAN indicate recognition by pointing with the left hand (controlled by right hemisphere).\n\nWhy others are wrong:\n(A) Verbal identification requires the left hemisphere, which didn't receive the input\n(C) The right hemisphere DOES perceive the image — it just can't express it verbally\n(D) Both responses would only be possible if the image reached both hemispheres (intact corpus callosum)"},
        {domainId:1, q:"Wernicke's encephalopathy is caused by a deficiency of:", options:["Vitamin B12","Thiamine (Vitamin B1)","Iron","Folic acid"], answer:1, difficulty:"medium", rationale:"Correct: (B) Thiamine (B1) deficiency, most commonly from chronic alcoholism, causes Wernicke's encephalopathy (confusion, ataxia, ophthalmoplegia). If untreated, it progresses to Korsakoff's syndrome (amnesia, confabulation).\n\nWhy others are wrong:\n(A) B12 deficiency → pernicious anemia, peripheral neuropathy, and subacute combined degeneration of the spinal cord\n(C) Iron deficiency → anemia (fatigue, weakness), not typically neurological encephalopathy\n(D) Folic acid deficiency → megaloblastic anemia and neural tube defects in fetal development, not Wernicke's"},
        {domainId:1, q:"The action potential follows which sequence?", options:["Depolarization → hyperpolarization → resting potential","Resting potential → depolarization → repolarization → hyperpolarization","Hyperpolarization → depolarization → resting potential","Depolarization → resting potential → repolarization"], answer:1, difficulty:"medium", rationale:"Correct: (B) The action potential sequence: resting (-70mV) → depolarization (Na+ influx, rises to +30mV) → repolarization (K+ efflux, returns toward resting) → hyperpolarization (brief overshoot below resting) → resting restored.\n\nWhy others are wrong:\n(A) Skips the resting potential start and the repolarization phase\n(C) Starts with hyperpolarization, which only occurs AFTER an action potential\n(D) Places repolarization after resting potential, which reverses the actual sequence"},
        {domainId:1, q:"Broca's aphasia is characterized by:", options:["Fluent but meaningless speech","Nonfluent, effortful speech with relatively preserved comprehension","Inability to repeat words spoken by others","Complete inability to understand spoken language"], answer:1, difficulty:"easy", rationale:"Correct: (B) Broca's aphasia produces telegraphic, effortful speech ('broken' output) but relatively preserved comprehension. Patients know what they want to say but struggle to produce it.\n\nWhy others are wrong:\n(A) Fluent meaningless speech → Wernicke's aphasia (left temporal damage)\n(C) Inability to repeat → conduction aphasia (damage to arcuate fasciculus connecting Broca's and Wernicke's)\n(D) Complete comprehension failure → global aphasia or severe Wernicke's"},
        {domainId:1, q:"The neurotransmitter most directly involved in the reward pathway is:", options:["Serotonin","GABA","Acetylcholine","Dopamine"], answer:3, difficulty:"easy", rationale:"Correct: (D) Dopamine is the primary neurotransmitter in the mesolimbic reward pathway (ventral tegmental area → nucleus accumbens). It mediates pleasure, motivation, and reinforcement learning.\n\nWhy others are wrong:\n(A) Serotonin → primarily involved in mood regulation, sleep, and appetite, not the reward pathway\n(B) GABA → primary inhibitory neurotransmitter; reduces neural activity rather than signaling reward\n(C) Acetylcholine → involved in memory, learning, and muscle activation, not the reward circuit"},
        {domainId:1, q:"Seasonal Affective Disorder (SAD) has been linked to dysregulation of:", options:["Dopamine in the basal ganglia","Melatonin and circadian rhythms","Acetylcholine in the hippocampus","Endorphins in the brainstem"], answer:1, difficulty:"medium", rationale:"Correct: (B) SAD is linked to disrupted circadian rhythms and abnormal melatonin secretion due to reduced daylight in winter months. Light therapy (10,000 lux) is an effective treatment that helps reset the circadian clock.\n\nWhy others are wrong:\n(A) Basal ganglia dopamine dysregulation → Parkinson's disease, not SAD\n(C) Hippocampal acetylcholine problems → Alzheimer's disease and memory impairment\n(D) Brainstem endorphins → related to pain modulation, not seasonal mood changes"},
        {domainId:1, q:"Which structure is responsible for coordinating the endocrine system?", options:["Thalamus","Hippocampus","Hypothalamus","Amygdala"], answer:2, difficulty:"easy", rationale:"Correct: (C) The hypothalamus links the nervous system to the endocrine system via the pituitary gland. It releases hormones that control the pituitary, which in turn regulates the thyroid, adrenals, and gonads.\n\nWhy others are wrong:\n(A) Thalamus → sensory relay station; routes sensory info to cortex, not endocrine control\n(B) Hippocampus → memory consolidation, not endocrine regulation\n(D) Amygdala → emotional processing, especially fear; not primary endocrine coordinator"},
        {domainId:1, q:"The blood-brain barrier is most permeable to:", options:["Large water-soluble molecules","Small fat-soluble molecules","Proteins and antibodies","Neurotransmitters in the bloodstream"], answer:1, difficulty:"medium", rationale:"Correct: (B) Small, lipophilic (fat-soluble) molecules like oxygen, CO2, alcohol, and nicotine cross the BBB easily because they dissolve through the lipid bilayer of endothelial cells.\n\nWhy others are wrong:\n(A) Large water-soluble molecules are too big and hydrophilic to cross\n(C) Proteins/antibodies are far too large — this protects the brain from most infections but complicates drug delivery\n(D) Peripheral neurotransmitters cannot cross the BBB (which is why L-DOPA, a precursor, is used instead of dopamine)"},
        {domainId:1, q:"A CT scan is MOST useful for detecting:", options:["Real-time neural activity","Structural abnormalities like tumors, bleeding, or fractures","Neurotransmitter levels","White matter tract connectivity"], answer:1, difficulty:"easy", rationale:"Correct: (B) CT (Computed Tomography) uses X-rays to create cross-sectional images useful for detecting structural problems — tumors, hemorrhages, skull fractures, hydrocephalus.\n\nWhy others are wrong:\n(A) Real-time activity → EEG (electrical) or fMRI (metabolic)\n(C) Neurotransmitter levels → PET scans with radioactive tracers can estimate this\n(D) White matter tracts → DTI (Diffusion Tensor Imaging), a specialized MRI technique"},

        // ===== Domain 2: Cognitive-Affective (12) =====
        {domainId:2, q:"According to the levels of processing framework (Craik & Lockhart), which study strategy would produce the BEST retention?", options:["Reading the definition repeatedly","Writing the word 10 times","Creating a personal example relating the concept to your own life","Highlighting the text in a textbook"], answer:2, difficulty:"easy", rationale:"Correct: (C) Self-referential processing (connecting material to personal experience) produces the deepest encoding. This is deeper than semantic processing, which is already deeper than structural or phonemic processing.\n\nWhy others are wrong:\n(A) Rote re-reading is shallow maintenance rehearsal — it keeps info in short-term memory but doesn't promote deep encoding\n(B) Writing the word repeatedly is still shallow/structural processing\n(D) Highlighting is passive and doesn't require deep processing — it creates an illusion of learning"},
        {domainId:2, q:"A person who can remember the exact details of where they were when they heard about 9/11 is demonstrating:", options:["Semantic memory","Flashbulb memory","Procedural memory","Prospective memory"], answer:1, difficulty:"easy", rationale:"Correct: (B) Flashbulb memories are vivid, detailed memories of emotionally significant events. While subjectively compelling, research shows they are not necessarily more accurate than ordinary memories — just more confident and vivid.\n\nWhy others are wrong:\n(A) Semantic memory = general knowledge/facts ('9/11 was a terrorist attack') without personal context\n(C) Procedural memory = motor skills and habits (how to ride a bike)\n(D) Prospective memory = remembering to do something in the future"},
        {domainId:2, q:"The serial position effect predicts that in a list-learning task, words remembered best will be:", options:["Only those in the middle of the list","Those at the beginning and end of the list","Only those at the end of the list","Randomly distributed throughout the list"], answer:1, difficulty:"easy", rationale:"Correct: (B) The serial position effect produces a U-shaped recall curve: primacy effect (early items rehearsed into LTM) + recency effect (late items still in STM). Middle items receive the least rehearsal and are least available in STM.\n\nWhy others are wrong:\n(A) Middle items are actually remembered WORST\n(C) Recency effect covers only end items; primacy covers beginning items — both contribute\n(D) The pattern is systematic (U-shaped), not random"},
        {domainId:2, q:"According to Lazarus's cognitive appraisal theory, stress depends on:", options:["The objective severity of the stressor","Whether the person appraises the situation as threatening AND their coping resources as insufficient","Physiological arousal only","The number of stressors present simultaneously"], answer:1, difficulty:"medium", rationale:"Correct: (B) Lazarus (1984) proposed that stress results from two appraisals: primary ('Is this threatening?') and secondary ('Can I cope?'). Stress only occurs when the threat appraisal exceeds the coping appraisal.\n\nWhy others are wrong:\n(A) Objective severity alone doesn't determine stress — the same event is stressful to one person but not another\n(C) Physiological arousal alone = James-Lange theory, not Lazarus's cognitive model\n(D) Number of stressors matters but the appraisal of each one determines its impact"},
        {domainId:2, q:"The 'cocktail party effect' demonstrates:", options:["That alcohol impairs cognitive functioning","Selective attention — the ability to focus on one stimulus while filtering out others","That social situations improve memory","That noise always impairs learning"], answer:1, difficulty:"easy", rationale:"Correct: (B) The cocktail party effect (Cherry, 1953) shows we can selectively attend to one conversation in a noisy environment. We also detect personally relevant information (like our name) in the unattended channel, showing some processing of 'ignored' stimuli.\n\nWhy others are wrong:\n(A) Nothing to do with alcohol — it's about auditory selective attention\n(C) Social situations don't inherently improve memory\n(D) Noise doesn't always impair learning — we can filter it via selective attention"},
        {domainId:2, q:"Retrograde amnesia involves:", options:["Inability to form new memories after brain damage","Loss of memories formed BEFORE the brain damage","Forgetting how to perform learned motor skills","Temporary memory loss during sleep"], answer:1, difficulty:"easy", rationale:"Correct: (B) Retrograde amnesia = loss of memories from BEFORE the injury. Typically follows a temporal gradient (Ribot's Law): recent memories are more vulnerable than remote memories.\n\nWhy others are wrong:\n(A) Inability to form NEW memories = anterograde amnesia (the other direction — 'going forward')\n(C) Motor skill forgetting is very rare because procedural memory is stored in cerebellum/basal ganglia, which are usually spared\n(D) Sleep doesn't cause amnesia; sleep actually consolidates memories"},
        {domainId:2, q:"Which of the following is an example of negative reinforcement?", options:["Giving a child a candy for good behavior","Taking away a teenager's phone for misbehavior","Taking an aspirin to relieve a headache","Yelling at a student for talking in class"], answer:2, difficulty:"medium", rationale:"Correct: (C) Taking aspirin REMOVES an aversive stimulus (headache pain), which INCREASES the likelihood of taking aspirin in the future. Negative reinforcement = removing something unpleasant → behavior increases.\n\nWhy others are wrong:\n(A) Giving candy = positive reinforcement (adding something pleasant → behavior increases)\n(B) Taking away phone = negative punishment (removing something pleasant → behavior decreases)\n(D) Yelling = positive punishment (adding something aversive → behavior decreases)"},
        {domainId:2, q:"The Garcia effect (conditioned taste aversion) is significant because it demonstrates that:", options:["Classical conditioning always requires many pairings","All stimuli are equally associable with all responses","Biological preparedness influences what associations are easily learned","Operant conditioning is superior to classical conditioning"], answer:2, difficulty:"medium", rationale:"Correct: (C) Garcia & Koelling (1966) showed that rats easily associated taste (not lights/sounds) with illness, even with long delays. This challenged the equipotentiality premise — organisms are biologically prepared to learn certain associations more easily than others.\n\nWhy others are wrong:\n(A) Taste aversion can occur in ONE trial — it doesn't require multiple pairings\n(B) This is exactly what the study DISproved — stimuli are NOT equally associable\n(D) The Garcia effect is a classical conditioning phenomenon and doesn't compare operant conditioning"},
        {domainId:2, q:"The Stroop effect demonstrates:", options:["The superiority of bottom-up processing","Interference between automatic and controlled processing","That reading is a controlled process","That color perception is automatic"], answer:1, difficulty:"medium", rationale:"Correct: (B) The Stroop effect (naming the ink color of a color word, e.g., 'RED' in blue ink) demonstrates interference between automatic processing (reading) and controlled processing (color naming). Reading is so automatic it interferes with the controlled task.\n\nWhy others are wrong:\n(A) It actually demonstrates the power of top-down (automatic reading) over bottom-up color processing\n(C) Reading is AUTOMATIC, not controlled — that's why it interferes\n(D) Color naming requires controlled processing; the interference comes from automatic reading"},
        {domainId:2, q:"According to the Atkinson-Shiffrin model, information flows through memory in which order?", options:["Long-term → short-term → sensory","Working memory → episodic buffer → long-term","Sensory → short-term → long-term","Short-term → sensory → long-term"], answer:2, difficulty:"easy", rationale:"Correct: (C) The modal model proposes a linear flow: sensory memory (brief storage, < 1 sec for iconic, < 4 sec for echoic) → short-term memory (limited capacity, ~20-30 sec) → long-term memory (unlimited, permanent) via rehearsal.\n\nWhy others are wrong:\n(A) Reverses the flow — you can't retrieve from LTM without first encoding through sensory and STM\n(B) Working memory and episodic buffer are from Baddeley's model, not Atkinson-Shiffrin\n(D) Places short-term before sensory, but information must first be sensed before being held in STM"},
        {domainId:2, q:"Observational learning (Bandura) requires which four processes?", options:["Stimulus, response, reinforcement, punishment","Attention, retention, reproduction, motivation","Encoding, storage, retrieval, forgetting","Assimilation, accommodation, equilibration, schemas"], answer:1, difficulty:"medium", rationale:"Correct: (B) Bandura's four processes: Attention (noticing the model), Retention (remembering the behavior), Reproduction (physical ability to perform it), Motivation (incentive or reinforcement to perform it).\n\nWhy others are wrong:\n(A) These are basic operant conditioning terms from Skinner, not Bandura's observational learning\n(C) These are general memory processes, not specific to observational learning\n(D) These are Piaget's concepts of cognitive development, not Bandura's social learning theory"},
        {domainId:2, q:"Seligman's concept of 'learned helplessness' was revised to emphasize:", options:["Behavioral reinforcement schedules","Attributional style — how people explain negative events","Observational learning from helpless models","Biological predisposition to depression"], answer:1, difficulty:"medium", rationale:"Correct: (B) The revised learned helplessness theory (Abramson, Seligman, & Teasdale, 1978) introduced attributional style: people who attribute negative events to internal, stable, and global causes are most vulnerable to helplessness and depression.\n\nWhy others are wrong:\n(A) Reinforcement schedules are from Skinner's operant conditioning, not the helplessness revision\n(C) Observational learning is Bandura's concept, not part of the helplessness revision\n(D) Biological factors may contribute but the revision specifically emphasizes cognitive attributional patterns"},

        // ===== Domain 3: Social & Cultural (8) =====
        {domainId:3, q:"The concept of 'cultural humility' differs from 'cultural competence' primarily by:", options:["Emphasizing a fixed endpoint of knowledge about other cultures","Emphasizing an ongoing, self-reflective process and acknowledging power imbalances","Being less important in clinical practice","Focusing only on racial differences"], answer:1, difficulty:"medium", rationale:"Correct: (B) Cultural humility (Tervalon & Murray-García, 1998) is a lifelong process of self-reflection, recognizing power imbalances, and developing mutually respectful partnerships. It acknowledges that one can never fully 'master' another culture.\n\nWhy others are wrong:\n(A) Cultural humility rejects the idea of a fixed endpoint — learning is ongoing and one can never be 'done'\n(C) Cultural humility is considered equally or more important than competence in modern multicultural practice\n(D) Cultural humility applies to ALL dimensions of diversity, not just race"},
        {domainId:3, q:"Leon Festinger's cognitive dissonance theory predicts that a person who is paid $1 (vs. $20) to lie about a boring task will:", options:["Report the task as more boring","Report the task as more enjoyable","Show no change in attitude","Refuse to participate in the study"], answer:1, difficulty:"hard", rationale:"Correct: (B) The $1 group lacks sufficient external justification for lying, creating more dissonance. To reduce dissonance, they change their attitude to believe the task was actually enjoyable. The $20 group has sufficient external justification and experiences less dissonance.\n\nWhy others are wrong:\n(A) They'd only find it MORE boring if dissonance drove them to contrast their experience with the lie\n(C) The insufficient justification ($1) specifically produces attitude change — this is the study's key finding\n(D) Festinger & Carlsmith's participants did not refuse; they participated and showed predictable attitude changes"},
        {domainId:3, q:"Individualistic cultures tend to show MORE of which attribution pattern compared to collectivistic cultures?", options:["Situational attributions for others' behavior","The fundamental attribution error","Group-based attributions","External attributions for success"], answer:1, difficulty:"medium", rationale:"Correct: (B) Individualistic cultures (US, Western Europe) show stronger fundamental attribution error — overemphasizing personality traits and underestimating situations when explaining others' behavior. This reflects the cultural value placed on individual agency.\n\nWhy others are wrong:\n(A) Situational attributions are MORE common in collectivistic cultures, which emphasize contextual factors\n(C) Group-based attributions are more characteristic of collectivistic cultures\n(D) External attributions for success are more common in collectivistic cultures; individualistic cultures show self-serving bias (internal attributions for success)"},
        {domainId:3, q:"Social identity theory (Tajfel & Turner) proposes that self-esteem is partly derived from:", options:["Individual achievements exclusively","Group memberships and the perceived status of one's in-groups","Genetic factors","Childhood attachment experiences"], answer:1, difficulty:"medium", rationale:"Correct: (B) Social identity theory proposes that part of our self-concept comes from group memberships. We enhance self-esteem by favoring our in-groups over out-groups, which explains intergroup discrimination even in minimal group conditions.\n\nWhy others are wrong:\n(A) Social identity theory specifically addresses SOCIAL (group-based) sources of self-esteem, not just individual\n(C) Genetic factors relate to biological approaches, not social identity theory\n(D) Attachment experiences relate to attachment theory (Bowlby/Ainsworth), not Tajfel's social identity framework"},
        {domainId:3, q:"The 'foot-in-the-door' technique works because of:", options:["Cognitive dissonance reduction","Self-perception theory — people infer attitudes from their past behavior","Fear of social rejection","Classical conditioning"], answer:1, difficulty:"medium", rationale:"Correct: (B) After complying with a small request, people observe their own behavior and infer 'I must be the kind of person who does these things' (Bem's self-perception theory). This makes them more likely to comply with the larger request to remain consistent.\n\nWhy others are wrong:\n(A) While dissonance can play a role, self-perception theory is the primary explanation (especially when initial attitude is weak)\n(C) Fear of rejection may contribute but isn't the primary mechanism — FITD works even without social pressure\n(D) Classical conditioning involves stimulus-response associations, not the self-concept processes that drive FITD"},
        {domainId:3, q:"Which theory best explains why people may not help in emergencies when others are present?", options:["Social identity theory","Diffusion of responsibility","Attribution theory","Cognitive dissonance theory"], answer:1, difficulty:"easy", rationale:"Correct: (B) Diffusion of responsibility (Latané & Darley) = each bystander feels less personal responsibility when others are present. Combined with pluralistic ignorance (looking to others who also aren't acting) and evaluation apprehension (fear of embarrassment).\n\nWhy others are wrong:\n(A) Social identity theory explains in-group favoritism, not bystander inaction\n(C) Attribution theory explains how people explain behavior, not why they fail to help\n(D) Cognitive dissonance explains attitude change after inconsistent behavior, not emergency helping"},
        {domainId:3, q:"Cialdini identified which principles of persuasion?", options:["Trust, empathy, and congruence","Reciprocity, commitment/consistency, social proof, authority, liking, and scarcity","Id, ego, and superego","Precontemplation, contemplation, and action"], answer:1, difficulty:"medium", rationale:"Correct: (B) Cialdini's six principles: Reciprocity (returning favors), Commitment/Consistency (acting consistently with past actions), Social Proof (following others), Authority (complying with experts), Liking (persuaded by those we like), Scarcity (valuing what's limited).\n\nWhy others are wrong:\n(A) These are Rogers' core conditions for person-centered therapy\n(C) These are Freud's personality structures\n(D) These are stages from the Transtheoretical Model of behavior change"},
        {domainId:3, q:"According to relative deprivation theory, social unrest occurs when:", options:["People are in absolute poverty","People perceive a discrepancy between what they have and what they believe they deserve","All group members are equally deprived","Government resources are limited"], answer:1, difficulty:"medium", rationale:"Correct: (B) Relative deprivation theory (Stouffer, 1949; Runciman, 1966) proposes that discontent stems not from absolute deprivation but from the perceived gap between expectations and reality. Paradoxically, slightly improving conditions can increase unrest by raising expectations.\n\nWhy others are wrong:\n(A) Absolute poverty alone doesn't predict social unrest — the perception of unfairness does\n(C) If everyone is equally deprived, there's less relative deprivation and potentially less unrest\n(D) Limited resources are only destabilizing when people perceive inequitable distribution"},

        // ===== Domain 4: Growth & Lifespan (8) =====
        {domainId:4, q:"A child who can sort objects by color OR shape, but not by both simultaneously, is likely in which Piagetian stage?", options:["Sensorimotor","Preoperational","Concrete operational","Formal operational"], answer:1, difficulty:"medium", rationale:"Correct: (B) Preoperational children (2-7) exhibit centration — focusing on one dimension at a time. They can't simultaneously consider multiple attributes, which also explains their failure to conserve.\n\nWhy others are wrong:\n(A) Sensorimotor (0-2): too young for this task; relies on sensory-motor exploration, not classification\n(C) Concrete operational (7-11): CAN sort by multiple dimensions simultaneously and understand class inclusion\n(D) Formal operational (11+): can handle abstract and hypothetical classification well beyond this task"},
        {domainId:4, q:"According to Bowlby, attachment behaviors serve what primary function?", options:["Obtaining food and nutrition","Maintaining proximity to the caregiver for survival/protection","Learning social skills","Developing language"], answer:1, difficulty:"easy", rationale:"Correct: (B) Bowlby's ethological attachment theory proposes that attachment behaviors (crying, clinging, following) evolved to maintain proximity to caregivers, ensuring protection from predators and environmental threats.\n\nWhy others are wrong:\n(A) Harlow's studies disproved the 'cupboard theory' — attachment is about comfort/security, not food\n(C) Social skill development is a later benefit of secure attachment, not the primary evolutionary function\n(D) Language development occurs within attachment relationships but isn't the primary function of attachment behavior"},
        {domainId:4, q:"The term 'scaffolding' was coined by:", options:["Piaget","Vygotsky","Bruner","Erikson"], answer:2, difficulty:"hard", rationale:"Correct: (C) Jerome Bruner, Wood, and Ross (1976) coined the term 'scaffolding.' While the concept builds on Vygotsky's ZPD, Vygotsky himself never used the word 'scaffolding.'\n\nWhy others are wrong:\n(A) Piaget's theory emphasizes self-directed discovery, with less emphasis on adult-guided instruction\n(B) Vygotsky introduced the ZPD concept that scaffolding builds upon, but the TERM was coined by Bruner\n(D) Erikson's theory focuses on psychosocial stages, not instructional scaffolding"},
        {domainId:4, q:"The Strange Situation procedure classifies attachment into types based primarily on:", options:["The child's behavior while playing alone","The child's behavior during separation FROM and reunion WITH the caregiver","The caregiver's behavior during feeding","The child's temperament assessment scores"], answer:1, difficulty:"easy", rationale:"Correct: (B) Ainsworth's procedure specifically examines the child's response to separation (distress level) and especially REUNION behavior (how the child responds when the caregiver returns).\n\nWhy others are wrong:\n(A) Solitary play behavior may be observed but isn't the primary classification criterion\n(C) Feeding behavior is not observed in the Strange Situation; this relates to the outdated 'cupboard theory'\n(D) Temperament contributes to attachment behavior but the classification is based on observed reunion behavior, not temperament scores"},
        {domainId:4, q:"According to Erikson, the primary developmental task of adolescence is:", options:["Trust vs. mistrust","Industry vs. inferiority","Identity vs. role confusion","Intimacy vs. isolation"], answer:2, difficulty:"easy", rationale:"Correct: (C) Identity vs. role confusion (ages 12-18) involves developing a coherent sense of self, values, and life direction. Successful resolution produces fidelity — the ability to commit to others and to ideologies.\n\nWhy others are wrong:\n(A) Trust vs. mistrust (0-1) = infancy — can I trust the world? Resolved through consistent caregiving\n(B) Industry vs. inferiority (6-12) = school age — can I master skills? Resolved through academic and social competence\n(D) Intimacy vs. isolation (18-40) = young adulthood — can I form deep relationships? Follows identity formation"},
        {domainId:4, q:"A child who believes that the sun follows them when they walk is demonstrating:", options:["Object permanence","Egocentrism","Theory of mind","Metacognition"], answer:1, difficulty:"easy", rationale:"Correct: (B) Egocentrism in the preoperational stage makes children unable to distinguish their own perspective from others' or from the physical world. They assume the world revolves around them, literally.\n\nWhy others are wrong:\n(A) Object permanence = understanding objects exist when not seen; develops in sensorimotor stage\n(C) Theory of mind = understanding others have different mental states; emerges ~age 4 and would counteract this belief\n(D) Metacognition = thinking about thinking; develops in formal operational stage (11+)"},
        {domainId:4, q:"Which theorist proposed that moral development in women emphasizes an ethic of care rather than justice?", options:["Kohlberg","Piaget","Gilligan","Erikson"], answer:2, difficulty:"easy", rationale:"Correct: (C) Carol Gilligan (1982, 'In a Different Voice') argued that Kohlberg's emphasis on justice/rights reflected male-oriented moral reasoning. She proposed that women may emphasize care, responsibility, and relationships in moral decision-making.\n\nWhy others are wrong:\n(A) Kohlberg's theory emphasizes justice and rights — Gilligan was critiquing his model\n(B) Piaget studied moral development in children (moral realism → moral relativism) but didn't focus on gender differences\n(D) Erikson's theory addresses psychosocial development, not moral reasoning per se"},
        {domainId:4, q:"Which of the following BEST describes the concept of 'neurulation' in prenatal development?", options:["The fertilization of the egg by the sperm","The formation of the neural tube from the neural plate","The implantation of the blastocyst in the uterine wall","The development of the placenta"], answer:1, difficulty:"hard", rationale:"Correct: (B) Neurulation (weeks 3-4) is the process where the neural plate folds to form the neural tube, which becomes the brain and spinal cord. Failure to close completely causes neural tube defects (e.g., spina bifida, anencephaly).\n\nWhy others are wrong:\n(A) Fertilization = conception; occurs before implantation and well before neurulation\n(C) Implantation = the blastocyst embedding in the uterine wall (~day 6-12); occurs before neurulation\n(D) Placenta development occurs during the embryonic period but is a distinct process from neural tube formation"},

        // ===== Domain 5: Assessment (8) =====
        {domainId:5, q:"Cronbach's alpha is used to measure:", options:["Test-retest reliability","Internal consistency reliability","Inter-rater reliability","Criterion validity"], answer:1, difficulty:"easy", rationale:"Correct: (B) Cronbach's alpha measures internal consistency — the degree to which all items on a test measure the same construct. Values range from 0 to 1, with .70+ generally considered acceptable and .80+ good.\n\nWhy others are wrong:\n(A) Test-retest reliability measures stability over time by correlating scores from two administrations\n(C) Inter-rater reliability measures agreement between raters/observers (Cohen's kappa, ICC)\n(D) Criterion validity measures how well test scores predict an external criterion, not internal consistency"},
        {domainId:5, q:"A z-score of -1.5 means the score falls:", options:["1.5 standard deviations above the mean","1.5 standard deviations below the mean","At the 15th percentile exactly","At the mean"], answer:1, difficulty:"easy", rationale:"Correct: (B) A negative z-score indicates the score is below the mean. -1.5 means the score is 1.5 standard deviations below the mean, corresponding to approximately the 7th percentile.\n\nWhy others are wrong:\n(A) A score 1.5 SDs ABOVE the mean would be z = +1.5\n(C) z = -1.5 corresponds to approximately the 7th percentile, not the 15th (z = -1.0 ≈ 16th percentile)\n(D) At the mean would be z = 0"},
        {domainId:5, q:"The Thematic Apperception Test (TAT) asks clients to:", options:["Interpret inkblots","Tell stories about ambiguous pictures","Complete sentence stems","Draw pictures of family members"], answer:1, difficulty:"easy", rationale:"Correct: (B) The TAT (Murray, 1943) uses ambiguous pictures of people in various situations. Clients create stories about each picture, which are interpreted to reveal unconscious needs, motivations, and conflicts.\n\nWhy others are wrong:\n(A) Interpreting inkblots = Rorschach test (Exner's Comprehensive System)\n(C) Completing sentence stems = Sentence Completion Tests (Rotter Incomplete Sentences Blank)\n(D) Drawing pictures of family members = Kinetic Family Drawing (KFD) or similar projective drawing tests"},
        {domainId:5, q:"A test has high specificity when it:", options:["Correctly identifies most people who HAVE the condition (few false negatives)","Correctly identifies most people who do NOT have the condition (few false positives)","Has a high overall accuracy rate","Measures a very specific construct"], answer:1, difficulty:"medium", rationale:"Correct: (B) Specificity = true negative rate. A test with 95% specificity correctly identifies 95% of people without the condition, producing few false positives. Important for confirmatory testing.\n\nWhy others are wrong:\n(A) Correctly identifying those WITH the condition = sensitivity (true positive rate), not specificity\n(C) Overall accuracy combines both sensitivity and specificity but isn't what 'specificity' specifically means\n(D) Measuring a specific construct relates to construct validity, not the statistical concept of specificity"},
        {domainId:5, q:"The 'barnum effect' in assessment refers to:", options:["The tendency to interpret test results too conservatively","People accepting vague, general personality descriptions as uniquely descriptive of themselves","The influence of examiner characteristics on test scores","The tendency to give socially desirable responses"], answer:1, difficulty:"medium", rationale:"Correct: (B) The Barnum effect (Forer effect) is the tendency to accept vague, generalized personality statements as accurate self-descriptions ('You have unused potential'). Named after P.T. Barnum. This is why horoscopes seem accurate.\n\nWhy others are wrong:\n(A) Conservative interpretation isn't a named psychological phenomenon\n(C) Examiner influence on scores relates to examiner effects or experimenter bias\n(D) Giving socially desirable responses = social desirability bias, measured by scales like L and K on the MMPI"},
        {domainId:5, q:"Which is NOT a subtest index of the WAIS-V?", options:["Verbal Comprehension Index","Fluid Reasoning Index","Emotional Intelligence Index","Processing Speed Index"], answer:2, difficulty:"easy", rationale:"Correct: (C) Emotional Intelligence is not measured by the WAIS. The WAIS assesses cognitive abilities, not emotional abilities.\n\nWhy others are wrong (these ARE actual WAIS indices):\n(A) VCI measures verbal reasoning, vocabulary, and general knowledge\n(B) FRI measures novel problem-solving with nonverbal stimuli (matrix reasoning, figure weights)\n(D) PSI measures speed of simple cognitive tasks (coding, symbol search)"},
        {domainId:5, q:"The difference between an aptitude test and an achievement test is:", options:["Aptitude tests are always more reliable","Aptitude tests predict future performance while achievement tests measure past learning","Achievement tests are projective while aptitude tests are objective","There is no meaningful difference"], answer:1, difficulty:"easy", rationale:"Correct: (B) Aptitude tests (SAT, GRE) predict future potential/performance in a domain. Achievement tests (state exams, EPPP) measure what has already been learned. Both use similar item formats, but their intended purposes differ.\n\nWhy others are wrong:\n(A) Both can have similar reliability; the difference is purpose, not psychometric quality\n(C) Neither type is inherently projective or objective — both typically use objective formats\n(D) They differ in purpose: predicting future performance vs. measuring past learning"},
        {domainId:5, q:"Ceiling effects in testing occur when:", options:["Too many examinees score at or near the maximum","The test is too difficult for the population","The test takes too long to administer","The scoring criteria are too strict"], answer:0, difficulty:"easy", rationale:"Correct: (A) Ceiling effects occur when the test is too easy, causing many scores to cluster at the top. This reduces variability and makes it impossible to differentiate among high-ability test-takers.\n\nWhy others are wrong:\n(B) Test being too difficult = floor effect (scores cluster at the bottom), the opposite of ceiling\n(C) Test length is a practical issue but doesn't define ceiling effects\n(D) Strict scoring criteria could produce floor effects, not ceiling effects"},

        // ===== Domain 6: Treatment/Intervention (8) =====
        {domainId:6, q:"Dialectical Behavior Therapy (DBT) was originally developed to treat:", options:["Generalized anxiety disorder","Borderline personality disorder","Major depressive disorder","Schizophrenia"], answer:1, difficulty:"easy", rationale:"Correct: (B) Marsha Linehan developed DBT specifically for chronically suicidal individuals with borderline personality disorder. It combines CBT with mindfulness and dialectical philosophy.\n\nWhy others are wrong:\n(A) GAD is typically treated with CBT, SSRIs, or relaxation training — not DBT's primary target\n(C) MDD was not the original target; behavioral activation and CBT are first-line for depression\n(D) Schizophrenia is primarily treated with antipsychotic medication, not DBT"},
        {domainId:6, q:"The 'common factors' model of psychotherapy suggests that:", options:["Specific techniques are the most important determinant of outcomes","Therapeutic alliance, empathy, and positive expectations account for much of therapy's effectiveness","Only CBT has empirical support","Medication is always superior to psychotherapy"], answer:1, difficulty:"medium", rationale:"Correct: (B) The common factors model (Wampold) proposes that factors shared across therapies — alliance, empathy, expectations, therapist factors — account for more outcome variance than specific techniques.\n\nWhy others are wrong:\n(A) Research shows specific techniques account for relatively little outcome variance compared to common factors\n(C) Multiple therapies have strong empirical support (psychodynamic, humanistic, CBT, IPT)\n(D) Meta-analyses show psychotherapy and medication are often equally effective, with combination sometimes best"},
        {domainId:6, q:"Systematic desensitization differs from flooding in that it:", options:["Uses immediate exposure to the most feared stimulus","Pairs relaxation with gradually increasing anxiety stimuli","Does not involve any exposure to feared stimuli","Is only used for social phobia"], answer:1, difficulty:"easy", rationale:"Correct: (B) Systematic desensitization (Wolpe) uses a gradual fear hierarchy paired with relaxation (reciprocal inhibition). The client progresses step-by-step from least to most anxiety-provoking.\n\nWhy others are wrong:\n(A) Immediate exposure to the most feared stimulus = flooding/implosion, the opposite approach\n(C) Systematic desensitization absolutely involves exposure, just gradually through a hierarchy\n(D) It's used for many anxiety conditions — specific phobias, agoraphobia, test anxiety, not just social phobia"},
        {domainId:6, q:"In Acceptance and Commitment Therapy (ACT), 'cognitive defusion' refers to:", options:["Challenging and replacing irrational thoughts","Observing thoughts without being controlled by them","Suppressing unwanted thoughts","Increasing cognitive processing speed"], answer:1, difficulty:"medium", rationale:"Correct: (B) Cognitive defusion helps clients see thoughts as just thoughts — mental events that can be observed without being believed or acted upon. E.g., prefacing thoughts with 'I'm having the thought that...'\n\nWhy others are wrong:\n(A) Challenging/replacing thoughts = cognitive restructuring (CBT), not ACT — ACT doesn't try to change thought content\n(C) Thought suppression is counterproductive (ironic process theory) and is the opposite of ACT's approach\n(D) Processing speed is a neurocognitive ability, not a therapeutic technique"},
        {domainId:6, q:"The therapeutic technique of 'reframing' involves:", options:["Repeating the client's words back exactly","Offering a new perspective or interpretation of a situation","Teaching progressive muscle relaxation","Assigning homework between sessions"], answer:1, difficulty:"easy", rationale:"Correct: (B) Reframing presents a situation in a new light — changing the meaning without changing the facts. E.g., reframing a child's 'stubbornness' as 'persistence' or 'strong-willed.'\n\nWhy others are wrong:\n(A) Repeating words back exactly = simple reflection or parroting, not reframing\n(C) Progressive muscle relaxation is a behavioral relaxation technique (Jacobson), not reframing\n(D) Homework assignments are a general therapeutic strategy used in CBT, not the technique of reframing"},
        {domainId:6, q:"Lithium is the first-line pharmacological treatment for:", options:["Major depressive disorder","Bipolar disorder","Generalized anxiety disorder","ADHD"], answer:1, difficulty:"easy", rationale:"Correct: (B) Lithium is the gold-standard mood stabilizer for bipolar disorder, effective for both acute mania and long-term maintenance. It also has anti-suicidal properties unique among psychiatric medications.\n\nWhy others are wrong:\n(A) MDD first-line = SSRIs or SNRIs, not lithium (though lithium is sometimes used as augmentation)\n(C) GAD first-line = SSRIs, SNRIs, or buspirone\n(D) ADHD first-line = stimulants (methylphenidate, amphetamine) or non-stimulants (atomoxetine)"},
        {domainId:6, q:"In strategic family therapy, a 'paradoxical directive' involves:", options:["Giving straightforward advice","Prescribing the symptom or telling the family to continue the problematic behavior","Using empathic reflection","Teaching communication skills"], answer:1, difficulty:"medium", rationale:"Correct: (B) Paradoxical directives (Haley, Madanes) instruct the family to deliberately perform the symptom. This creates a therapeutic double-bind: if they comply, the symptom is now under voluntary control; if they resist the directive, the symptom stops.\n\nWhy others are wrong:\n(A) Straightforward advice = psychoeducation or directive therapy, not paradoxical\n(C) Empathic reflection = person-centered/Rogerian technique\n(D) Teaching communication skills = behavioral family therapy or Gottman method, not paradoxical intervention"},
        {domainId:6, q:"The dose-effect relationship in psychotherapy research shows:", options:["All clients need exactly 20 sessions","Most improvement occurs in the first few sessions with diminishing returns over time","Longer therapy is always better","Therapy must last at least one year to be effective"], answer:1, difficulty:"medium", rationale:"Correct: (B) Howard's (1986) dose-effect model: ~50% improve by session 8, ~75% by session 26. Early sessions show the most rapid gains (negatively accelerating curve), with diminishing returns.\n\nWhy others are wrong:\n(A) Clients vary widely in how many sessions they need — there is no fixed number\n(C) More is not always better; some clients respond quickly, and very long therapy has diminishing returns\n(D) Brief therapies (SFBT, single-session therapy) show that effective therapy can be much shorter than one year"},

        // ===== Domain 7: Research Methods (8) =====
        {domainId:7, q:"A Type II error occurs when:", options:["A true null hypothesis is rejected","A false null hypothesis fails to be rejected","The sample size is too large","The effect size is inflated"], answer:1, difficulty:"easy", rationale:"Correct: (B) Type II error (beta/false negative) = failing to reject a null hypothesis that IS false. You miss a real effect. Power (1-β) is the probability of correctly detecting a true effect.\n\nWhy others are wrong:\n(A) Rejecting a TRUE null hypothesis = Type I error (alpha/false positive), not Type II\n(C) Larger samples actually REDUCE Type II errors by increasing statistical power\n(D) Inflated effect sizes relate to publication bias or measurement error, not Type II error definition"},
        {domainId:7, q:"External validity refers to:", options:["Whether the IV was properly manipulated","Whether results can be generalized beyond the study","Whether confounds were controlled","Whether the measures are reliable"], answer:1, difficulty:"easy", rationale:"Correct: (B) External validity = generalizability of findings to other populations, settings, and times. Threatened by non-representative samples, artificial settings, and historical specificity.\n\nWhy others are wrong:\n(A) Proper IV manipulation relates to internal validity and treatment fidelity\n(C) Controlling confounds = internal validity (ability to make causal inferences)\n(D) Measure reliability is a psychometric property, not about generalizability"},
        {domainId:7, q:"In a positively skewed distribution:", options:["The mean equals the median","The mean is less than the median","The mean is greater than the median","The mode is greater than the mean"], answer:2, difficulty:"medium", rationale:"Correct: (C) Positive skew = tail to the right. The mean is pulled toward extreme high scores: Mode < Median < Mean. Think of income distribution — a few very high earners pull the mean up.\n\nWhy others are wrong:\n(A) Mean = median only in a perfectly symmetrical (normal) distribution\n(B) Mean LESS than median occurs in NEGATIVE skew (tail to the left)\n(D) In positive skew, mode < mean (mode is the peak, which is on the left side)"},
        {domainId:7, q:"An ANOVA is used instead of multiple t-tests because:", options:["ANOVA is more powerful than t-tests","Multiple t-tests inflate the Type I error rate","ANOVA can only be used with two groups","t-tests cannot compare means"], answer:1, difficulty:"medium", rationale:"Correct: (B) Running multiple t-tests (e.g., 3 groups = 3 comparisons) inflates familywise alpha. With α=.05 and 3 tests, the actual error rate ≈ .14, not .05. ANOVA controls this by testing all groups simultaneously.\n\nWhy others are wrong:\n(A) ANOVA isn't inherently more powerful — it controls error rate, which is the primary advantage\n(C) ANOVA is specifically designed for 3+ groups; with only 2 groups, ANOVA and t-test give identical results\n(D) t-tests absolutely compare means — they're just limited to comparing two means at a time"},
        {domainId:7, q:"A correlation of r = -.85 indicates:", options:["A weak negative relationship","A strong negative relationship","No relationship","A moderate positive relationship"], answer:1, difficulty:"easy", rationale:"Correct: (B) r = -.85 is a strong negative correlation — as one variable increases, the other strongly tends to decrease. The sign indicates direction; the absolute value (.85) indicates strength.\n\nWhy others are wrong:\n(A) |r| = .85 is far from weak — weak correlations are roughly |r| < .30\n(C) No relationship = r ≈ 0, not -.85\n(D) The negative sign means the relationship is negative (inverse), not positive"},
        {domainId:7, q:"Regression to the mean refers to:", options:["Outliers being removed from data","Extreme scores tending to move toward the average on retesting","The tendency for all scores to cluster around the mean","Statistical adjustment for confounds"], answer:1, difficulty:"medium", rationale:"Correct: (B) Regression to the mean: extreme scores on one measurement tend to be less extreme on subsequent measurements, simply due to natural variability. This can mimic treatment effects if not controlled.\n\nWhy others are wrong:\n(A) Outlier removal is a data cleaning decision, not regression to the mean\n(C) Scores naturally vary — regression to the mean describes the MOVEMENT of extreme scores, not overall clustering\n(D) Statistical adjustment for confounds involves techniques like ANCOVA or regression analysis, not this phenomenon"},
        {domainId:7, q:"A quasi-experimental design differs from a true experiment because it:", options:["Does not have a control group","Does not use random assignment to conditions","Cannot measure dependent variables","Is never used in psychology"], answer:1, difficulty:"easy", rationale:"Correct: (B) Quasi-experiments lack random assignment — participants are assigned to conditions based on pre-existing characteristics (e.g., gender, diagnosis, classroom). This limits causal inferences due to potential confounds.\n\nWhy others are wrong:\n(A) Quasi-experiments CAN have control/comparison groups — they just aren't randomly formed\n(C) Quasi-experiments absolutely measure DVs — that's how they assess outcomes\n(D) Quasi-experiments are VERY common in psychology, especially in clinical, educational, and community settings where randomization isn't feasible or ethical"},
        {domainId:7, q:"The purpose of a post-hoc test (e.g., Tukey's HSD) is to:", options:["Determine if the overall ANOVA is significant","Identify which specific group means differ after a significant ANOVA","Replace the need for an ANOVA","Test assumptions of normality"], answer:1, difficulty:"medium", rationale:"Correct: (B) After a significant omnibus ANOVA (which only tells you SOME groups differ), post-hoc tests determine WHICH specific pairs of means are significantly different while controlling familywise error.\n\nWhy others are wrong:\n(A) Whether the overall ANOVA is significant is determined by the F-test, not post-hoc tests\n(C) Post-hoc tests FOLLOW an ANOVA — they don't replace it; the ANOVA must be significant first\n(D) Testing normality uses Shapiro-Wilk, Kolmogorov-Smirnov, or Q-Q plots, not post-hoc tests"},

        // ===== Domain 8: Ethics & Professional Issues (8) =====
        {domainId:8, q:"The Tarasoff ruling established that therapists have a:", options:["Right to break confidentiality at any time","Duty to protect identifiable third parties from serious harm","Requirement to report all criminal behavior","License to share client records with family members"], answer:1, difficulty:"easy", rationale:"Correct: (B) Tarasoff v. Regents (1976) established the duty to protect when a client makes a credible threat against an identifiable victim. Protection may include warning the victim, notifying police, or hospitalizing the client.\n\nWhy others are wrong:\n(A) Confidentiality can only be broken in specific legally defined circumstances, not 'at any time'\n(C) Reporting all criminal behavior is NOT required — the duty is specifically about serious threats of harm to identifiable persons\n(D) Sharing records with family requires client authorization (or legal exception), not a blanket license"},
        {domainId:8, q:"Informed consent must include all of the following EXCEPT:", options:["Nature and purpose of treatment","Potential risks and benefits","The therapist's personal therapy history","The right to withdraw at any time"], answer:2, difficulty:"easy", rationale:"Correct: (C) The therapist's own therapy history is private and NOT part of informed consent. Disclosure of personal information is a boundary decision, not a requirement.\n\nWhy others are wrong:\n(A) Nature/purpose of treatment IS required — clients must know what they're consenting to\n(B) Risks and benefits ARE required — clients need this to make an informed decision\n(D) Right to withdraw IS required — participation must be voluntary and revocable"},
        {domainId:8, q:"A psychologist who provides services outside their area of competence is violating:", options:["Principle of Justice","Standard 2.01 (Boundaries of Competence)","Standard 5.01 (Avoidance of False Statements)","Principle of Fidelity and Responsibility"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Standard 2.01 requires psychologists to practice only within the boundaries of their competence based on education, training, supervised experience, or professional experience.\n\nWhy others are wrong:\n(A) Justice = fair and equitable treatment; relevant to access and bias, not competence boundaries\n(C) Standard 5.01 = avoiding false/deceptive public statements, not about competence in practice\n(D) Fidelity/Responsibility = establishing trust and professional obligations — related but not the specific standard violated"},
        {domainId:8, q:"Dual relationships are MOST problematic when they:", options:["Occur in rural settings","Could reasonably impair objectivity or risk exploitation","Involve seeing a client at the grocery store","Are between colleagues"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Standard 3.05 prohibits multiple relationships that could reasonably impair objectivity, competence, or effectiveness, or risk exploitation or harm to the client.\n\nWhy others are wrong:\n(A) Rural settings make some dual relationships unavoidable, but the setting itself doesn't make them problematic — it's the impact on the relationship\n(C) Incidental encounters (grocery store) are not dual relationships — they're chance meetings that don't involve an additional role\n(D) Colleague relationships are generally not dual relationships in the APA sense unless there's a power differential or conflicting role"},
        {domainId:8, q:"A psychologist is ethically obligated to maintain records for:", options:["1 year after last contact","At least 7 years after last contact (longer for minors)","Only during active treatment","Indefinitely, with no time limit"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA record-keeping guidelines recommend maintaining records for at least 7 years after last contact, and for minors, 3 years after the child reaches the age of majority if that is longer.\n\nWhy others are wrong:\n(A) 1 year is far too short — many legal and clinical situations require access to older records\n(C) Records are needed after treatment ends for continuity of care, legal protection, and potential future requests\n(D) While longer retention is sometimes prudent, indefinite retention is not required and creates storage/security burdens"},
        {domainId:8, q:"HIPAA's 'minimum necessary' standard requires:", options:["Sharing all available information when requested","Disclosing only the information needed for the specific purpose","Never sharing any client information","Sharing information only with other psychologists"], answer:1, difficulty:"medium", rationale:"Correct: (B) The minimum necessary standard requires covered entities to limit PHI disclosures to the minimum amount needed to accomplish the intended purpose of the use or disclosure.\n\nWhy others are wrong:\n(A) Sharing ALL information violates the minimum necessary principle — only what's needed should be disclosed\n(C) HIPAA permits sharing when authorized by the client or required by law — it doesn't prohibit all sharing\n(D) Information can be shared with other healthcare providers, insurers, or as legally required — not just psychologists"},
        {domainId:8, q:"A psychologist testifying as an expert witness should:", options:["Advocate for the party that hired them","Provide objective, unbiased opinions based on scientific evidence","Only discuss information that supports the hiring party's position","Refuse to acknowledge limitations of their testimony"], answer:1, difficulty:"medium", rationale:"Correct: (B) APA Standard 2.04 requires that expert testimony be based on sufficient facts/data and reliable principles. Psychologists must be objective regardless of which party retained them.\n\nWhy others are wrong:\n(A) Advocating for the hiring party violates objectivity — the psychologist's role is to inform, not advocate\n(C) Selectively presenting only supportive information is misleading and unethical\n(D) Acknowledging limitations is required by both ethics codes and legal standards — good experts discuss the boundaries of their conclusions"},
        {domainId:8, q:"When treating a minor, confidentiality:", options:["Does not apply because the parent has full access to all information","Is maintained with some limits, balancing the minor's privacy with parents' legal rights","Is absolute and parents cannot access any information","Only applies if the minor is over 16"], answer:1, difficulty:"medium", rationale:"Correct: (B) Treating minors requires balancing the minor's developing right to privacy with parents' legal rights to information. Psychologists should discuss these boundaries upfront with both the minor and parents.\n\nWhy others are wrong:\n(A) Parents do NOT have unlimited access — many states protect minor confidentiality in specific areas (substance abuse, sexual health, mental health)\n(C) Confidentiality is NOT absolute for minors — parents retain certain legal rights and mandatory reporting still applies\n(D) Age-based rules vary by state; many states grant some confidentiality rights before age 16"}
    ];

    batch6.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch6.length} additional questions (batch 6 — enhanced rationales).`);
})();


